'use client'
import { cn, useSignals } from '@cascivo/core'
import { builtin, t } from '@cascivo/i18n'
import type { HTMLAttributes } from 'react'
import styles from './tag.module.css'

export interface TagProps extends HTMLAttributes<HTMLSpanElement> {
  variant?: 'default' | 'info' | 'success' | 'warning' | 'error'
  size?: 'sm' | 'md'
  onDismiss?: () => void
  dismissLabel?: string
}

export function Tag({
  variant = 'default',
  size = 'md',
  onDismiss,
  dismissLabel,
  className,
  children,
  ...props
}: TagProps) {
  useSignals()
  const resolvedDismissLabel = dismissLabel ?? t(builtin.tag.dismiss)
  return (
    <span
      data-variant={variant}
      data-size={size}
      className={cn(styles['tag'], className)}
      {...props}
    >
      {children}
      {onDismiss && (
        <button
          type="button"
          className={styles['dismiss']}
          aria-label={resolvedDismissLabel}
          onClick={onDismiss}
        >
          ✕
        </button>
      )}
    </span>
  )
}

@layer cascivo.component {
  .tag {
    display: inline-flex;
    align-items: center;
    gap: var(--cascivo-space-1);
    font-family: var(--cascivo-font-sans);
    font-weight: var(--cascivo-font-medium);
    border-radius: var(--cascivo-radius-badge);
    white-space: nowrap;

    &[data-size='sm'] {
      padding-inline: var(--cascivo-space-2);
      padding-block: var(--cascivo-space-1);
      font-size: var(--cascivo-text-xs);
      line-height: 1;
    }

    &[data-size='md'] {
      padding-inline: var(--cascivo-space-3);
      padding-block: var(--cascivo-space-1);
      font-size: var(--cascivo-text-xs);
      line-height: var(--cascivo-leading-normal);
    }

    &[data-variant='default'] {
      background-color: var(--cascivo-color-bg-subtle);
      color: var(--cascivo-color-text-subtle);
    }

    &[data-variant='info'] {
      background-color: var(--cascivo-color-info-subtle);
      color: var(--cascivo-color-info-foreground);
    }

    &[data-variant='success'] {
      background-color: var(--cascivo-color-success-subtle);
      color: var(--cascivo-color-success-foreground);
    }

    &[data-variant='warning'] {
      background-color: var(--cascivo-color-warning-subtle);
      color: var(--cascivo-color-warning-foreground);
    }

    &[data-variant='error'] {
      background-color: var(--cascivo-color-destructive-subtle);
      color: var(--cascivo-color-destructive-foreground);
    }
  }

  .dismiss {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: 0;
    margin-inline-end: calc(-1 * var(--cascivo-space-1));
    border: none;
    background: transparent;
    color: currentColor;
    font-size: inherit;
    line-height: 1;
    cursor: pointer;
    border-radius: var(--cascivo-radius-full);
    opacity: 0.7;
    transition: opacity var(--cascivo-duration-150) var(--cascivo-ease-out);

    &:hover {
      opacity: 1;
    }

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
      opacity: 1;
    }
  }
}
